import {
  makeEmailAddress,
  type OrgNextAppBootstrap,
  type OrgNextTenant,
  type OrgNextTenantMembership,
  type OrgNextUser,
} from "@workspace/api-client/org-next";

export const FAKE_ORG_API_TS = "2026-04-01T00:00:00.000Z";

export const fakeLocalUser: OrgNextUser = {
  id: 3,
  cognito_sub: "local-dev",
  created_at: FAKE_ORG_API_TS,
  email: makeEmailAddress("local@example.com"),
  updated_at: FAKE_ORG_API_TS,
};

export let fakeLocalTenants: OrgNextTenant[] = [
  {
    created_at: FAKE_ORG_API_TS,
    id: 1,
    name: "Local Org",
    org_id: null,
    tenant_type: "org",
    updated_at: FAKE_ORG_API_TS,
    vendor_id: null,
  },
];

export let fakeLocalMemberships: OrgNextTenantMembership[] = [
  {
    created_at: FAKE_ORG_API_TS,
    id: 1,
    tenant_id: 1,
    updated_at: FAKE_ORG_API_TS,
    user_id: 3,
  },
];

export function getFakeOrgNextAppBootstrap(): OrgNextAppBootstrap {
  const tenant = fakeLocalTenants[0] ?? null;

  return {
    accessibleTenants: fakeLocalTenants,
    currentMembership: fakeLocalMemberships[0] ?? null,
    currentTenant: tenant,
    currentUser: fakeLocalUser,
    memberships: fakeLocalMemberships,
    tenant,
    tenants: fakeLocalTenants,
    user: fakeLocalUser,
    users: [fakeLocalUser],
  };
}

export function addFakeLocalTenant(input: {
  name: string;
  tenant_type: "org" | "vendor";
}): OrgNextTenant {
  const nextId = Math.max(0, ...fakeLocalTenants.map((t) => t.id)) + 1;
  const tenant: OrgNextTenant = {
    created_at: FAKE_ORG_API_TS,
    id: nextId,
    name: input.name,
    org_id: null,
    tenant_type: input.tenant_type,
    updated_at: FAKE_ORG_API_TS,
    vendor_id: null,
  };

  fakeLocalTenants = [...fakeLocalTenants, tenant];

  const nextMembershipId =
    Math.max(0, ...fakeLocalMemberships.map((m) => m.id)) + 1;

  fakeLocalMemberships = [
    ...fakeLocalMemberships,
    {
      created_at: FAKE_ORG_API_TS,
      id: nextMembershipId,
      tenant_id: nextId,
      updated_at: FAKE_ORG_API_TS,
      user_id: fakeLocalUser.id,
    },
  ];

  return tenant;
}

import type { OrgNextTenantCreateRequest } from "@workspace/api-client/org-next";
import {
