} from "./fake-org-api-data";

function cloneJson<T>(value: T): T {
  return JSON.parse(JSON.stringify(value)) as T;
}

/**
 * In-memory JSON responses for org API paths when `VITE_ORG_NEXT_BYPASS_AUTH` is enabled.
 * Used by server `org-api` and the Vite dev middleware so SSR and the browser stay in sync.
 */
export function resolveLocalOrgApiStub(
  method: string,
  pathname: string,
  _searchParams: URLSearchParams,
  body: unknown,
): unknown {
  const m = method.toUpperCase();

  if (m === "GET" && pathname === "/up") {
    return { ok: true };
  }

  if (m === "GET" && pathname === "/users") {
    return cloneJson([fakeLocalUser]);
  }

  const userById = /^\/users\/(\d+)$/.exec(pathname);
  if (m === "GET" && userById) {
    const id = Number(userById[1]);
    if (id === fakeLocalUser.id) {
      return cloneJson(fakeLocalUser);
    }
    throw new Error(`Local stub: unknown user id ${id}`);
  }

  if (m === "GET" && pathname === "/tenants") {
    return cloneJson(fakeLocalTenants);
  }

  if (m === "GET" && pathname === "/tenant_memberships") {
    return cloneJson(fakeLocalMemberships);
  }

  if (m === "POST" && pathname === "/tenants") {
    const parsed = body as OrgNextTenantCreateRequest;
    const name = parsed.tenant?.name?.trim();
    const tenantType = parsed.tenant?.tenant_type;

    if (!name || (tenantType !== "org" && tenantType !== "vendor")) {
      throw new Error("Local stub: invalid tenant payload");
    }

    return cloneJson(
      addFakeLocalTenant({ name, tenant_type: tenantType }),
    );
  }

  if (m === "GET" && pathname === "/campaigns") {
    return cloneJson([
      {
        created_at: FAKE_ORG_API_TS,
        id: 101,
        name: "Spring Membership Drive",
        tenant_id: 1,
        updated_at: FAKE_ORG_API_TS,
      },
      {
        created_at: FAKE_ORG_API_TS,
        id: 102,
        name: "Neighborhood Yard Signs",
        tenant_id: 1,
        updated_at: FAKE_ORG_API_TS,
      },
      {
        created_at: FAKE_ORG_API_TS,
        id: 103,
        name: "Volunteer Kickoff",
        tenant_id: 1,
        updated_at: FAKE_ORG_API_TS,
      },
    ]);
  }

  const campaignById = /^\/campaigns\/(\d+)$/.exec(pathname);
  if (m === "GET" && campaignById) {
    const id = Number(campaignById[1]);
    const names: Record<number, string> = {
      101: "Spring Membership Drive",
      102: "Neighborhood Yard Signs",
      103: "Volunteer Kickoff",
    };
    const name = names[id];
    if (!name) {
      throw new Error(`Local stub: unknown campaign id ${id}`);
    }
    return cloneJson({
      created_at: FAKE_ORG_API_TS,
      id,
      name,
      tenant_id: 1,
      updated_at: FAKE_ORG_API_TS,
    });
  }

  throw new Error(`Local stub: unhandled ${m} ${pathname}`);
}

