import type { IncomingMessage } from "node:http";
import type { Plugin } from "vite";
import { loadEnv } from "vite";
import { resolveLocalOrgApiStub } from "./src/server/local-org-api-stub";

function readRequestBody(req: IncomingMessage): Promise<string> {
  return new Promise((resolve, reject) => {
    const chunks: Buffer[] = [];
    req.on("data", (chunk: Buffer) => {
      chunks.push(chunk);
    });
    req.on("end", () => {
      resolve(Buffer.concat(chunks).toString("utf8"));
    });
    req.on("error", reject);
  });
}

function isOrgApiDevPath(pathOnly: string): boolean {
  if (
    pathOnly === "/campaigns" ||
    pathOnly === "/tenant_memberships" ||
    pathOnly === "/tenants" ||
    pathOnly === "/up" ||
    pathOnly === "/users"
  ) {
    return true;
  }
  if (/^\/campaigns\/\d+$/.test(pathOnly)) {
    return true;
  }
  if (/^\/tenants\/\d+$/.test(pathOnly)) {
    return true;
  }
  if (/^\/users\/\d+$/.test(pathOnly)) {
    return true;
  }
  return false;
}

export function orgNextLocalOrgApiPlugin(): Plugin {
  return {
    configureServer(server) {
      server.middlewares.use(async (req, res, next) => {
        const env = loadEnv(server.config.mode, process.cwd(), "");
        if (env.VITE_ORG_NEXT_BYPASS_AUTH !== "true") {
          next();
          return;
        }

        const rawUrl = req.url ?? "/";
        const pathOnly = rawUrl.split("?")[0] ?? "/";

        if (!isOrgApiDevPath(pathOnly)) {
          next();
          return;
        }

        try {
          const method = (req.method ?? "GET").toUpperCase();
          let body: unknown;
          if (method === "PATCH" || method === "POST" || method === "PUT") {
            const raw = await readRequestBody(req);
            body = raw ? JSON.parse(raw) : undefined;
          }
          const url = new URL(rawUrl, "http://localhost");
          const payload = resolveLocalOrgApiStub(
            method,
            pathOnly,
            url.searchParams,
            body,
          );
          res.setHeader("Content-Type", "application/json");
          res.end(JSON.stringify(payload));
        } catch (error) {
          const message =
            error instanceof Error ? error.message : "Local org API stub error";
          res.statusCode = 404;
          res.setHeader("Content-Type", "application/json");
          res.end(JSON.stringify({ error: message }));
        }
      });
    },
    name: "org-next-local-org-api",
  };
}

